Here's an updated version of the `BaseRepository` class that allows you to find by a dynamic field:

```csharp
public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual async Task<T> FindAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> FindByDynamicAsync(string columnName, object value)
    {
        return await _dbSet
            .Where(e => e.GetType().GetProperty(columnName).GetValue(e) == value)
            .FirstOrDefaultAsync();
    }

    public virtual async Task<T> FindByDynamicAsync(string columnName, object value, params string[] includeProperties)
    {
        return await _dbSet
            .Include(includeProperties)
            .Where(e => e.GetType().GetProperty(columnName).GetValue(e) == value)
            .FirstOrDefaultAsync();
    }
}
```

